"use strict";(self.webpackChunkPradocument=self.webpackChunkPradocument||[]).push([[4211],{7141:(s,n,a)=>{a.r(n),a.d(n,{data:()=>e});const e={key:"v-4e74239e",path:"/guide/js/v-if%20%E5%88%A4%E6%96%AD%E5%85%83%E7%B4%A0%E6%BB%A1%E8%B6%B3%E5%A4%9A%E4%B8%AA%E6%9D%A1%E4%BB%B6%E7%9A%84%E5%86%99%E6%B3%95.html",title:"",lang:"en-US",frontmatter:{},excerpt:"",headers:[],filePathRelative:"guide/js/v-if 判断元素满足多个条件的写法.md",git:{updatedTime:1657620056e3,contributors:[{name:"孤城致幻",email:"Xast@123456",commits:1}]}}},8588:(s,n,a)=>{a.r(n),a.d(n,{default:()=>t});const e=(0,a(6252).uE)('<blockquote><p><code>v-if</code>判断type满足0的时候写法是：<code>v-if=&quot;type=== 0&quot;</code>，</p></blockquote><blockquote><p>那如果type同时要满足0，1，2三个值的时候，我们在<code>v-if</code>里用 <code>||</code> 并列写像这样：<code>v-if=&quot;type=== 0 || type=== 1 || type=== 2&quot;</code>，这样虽然可以，但如果条件太多了，就显得代码有点冗余！</p></blockquote><p>所以，最简便的写法就是：</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token comment">// [ ]里可以放字符串，数值等</span>\n\nv<span class="token operator">-</span><span class="token keyword">if</span><span class="token operator">=</span><span class="token string">&quot;[0,1,2].includes(type) &quot;</span>\n\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>我们还可以使用下面的方法:</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token literal-property property">methods</span><span class="token operator">:</span> <span class="token punctuation">{</span>\n    <span class="token comment">// 判断状态</span>\n    <span class="token function">matchState</span><span class="token punctuation">(</span>state <span class="token operator">=</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">,</span> reg<span class="token punctuation">)</span> <span class="token punctuation">{</span>\n        <span class="token keyword">return</span> <span class="token operator">!</span><span class="token operator">!</span><span class="token function">String</span><span class="token punctuation">(</span>state<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">match</span><span class="token punctuation">(</span>reg<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 返回true/false</span>\n    <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这个方法复用性高，适用于多个标签都需要用到此判断的情况下使用。</p><p>接下来我们就可以在需要的标签上使用：</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>v<span class="token operator">-</span><span class="token keyword">if</span><span class="token operator">=</span><span class="token string">&quot;matchState(type,/[012]/)&quot;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div>',9),p={},t=(0,a(3744).Z)(p,[["render",function(s,n){return e}]])},3744:(s,n)=>{n.Z=(s,n)=>{const a=s.__vccOpts||s;for(const[s,e]of n)a[s]=e;return a}}}]);